214:  afterEach(() => {
215:    clearGuild();
216:  });
218:  it('returns full session record by id', async () => {
219:    const result = await sessionShow.handler({ id: 'ses-00000001' });
220:    assert.equal(result.id, 'ses-00000001');
221:    assert.equal(result.status, 'completed');
222:    assert.equal(result.provider, 'claude-code');
