1:/**
2: * Claude Code Session Provider
3: *
4: * Apparatus plugin that implements AnimatorSessionProvider for the
5: * Claude Code CLI. The Animator discovers this via guild config:
6: *
7: *   guild.json["animator"]["sessionProvider"] = "claude-code"
8: *
9: * Launches sessions via the `claude` CLI in autonomous mode (--print)
10: * with --output-format stream-json for structured telemetry.
11: *
12: * Key design choice: uses async spawn() instead of spawnSync().
13: * This is required for stream-json transcript parsing, timeout enforcement,
14: * and future concurrent session support.
15: */
17:import { spawn } from 'node:child_process';
18:import fs from 'node:fs';
19:import os from 'node:os';
20:import path from 'node:path';
22:import type { Plugin } from '@shardworks/nexus-core';
23:import type {
24:  AnimatorSessionProvider,
25:  SessionProviderConfig,
26:  SessionProviderResult,
27:  SessionChunk,
28:} from '@shardworks/animator-apparatus';
30:import { startMcpHttpServer } from './mcp-server.ts';
31:import type { McpHttpHandle } from './mcp-server.ts';
33:// ── Session File Preparation ────────────────────────────────────────────
35:/** Prepared session files in a temp directory. */
36:interface PreparedSession {
37:  tmpDir: string;
38:  args: string[];
39:  /** If an MCP server was started, this handle closes it. */
40:  mcpHandle?: McpHttpHandle;
41:}
43:/**
44: * Prepare session files and build base CLI args.
45: *
46: * Writes system prompt to a temp directory. Builds the base args array
47: * including --resume support. When tools are provided, starts an
48: * in-process MCP HTTP server and writes --mcp-config.
49: *
50: * Caller is responsible for cleaning up tmpDir and calling mcpHandle.close().
51: */
52:async function prepareSession(config: SessionProviderConfig): Promise<PreparedSession> {
53:  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'nsg-session-'));
55:  const args: string[] = [
56:    '--setting-sources', 'user',
57:    '--dangerously-skip-permissions',
58:    '--model', config.model,
59:  ];
61:  if (config.systemPrompt) {
62:    const systemPromptPath = path.join(tmpDir, 'system-prompt.md');
63:    fs.writeFileSync(systemPromptPath, config.systemPrompt);
64:    args.push('--system-prompt-file', systemPromptPath);
65:  }
67:  // Resume an existing conversation
68:  if (config.conversationId) {
69:    args.push('--resume', config.conversationId);
70:  }
72:  // Tool-equipped session: start MCP HTTP server, write --mcp-config
73:  let mcpHandle: McpHttpHandle | undefined;
75:  if (config.tools && config.tools.length > 0) {
76:    const tools = config.tools.map((rt) => rt.definition);
77:    mcpHandle = await startMcpHttpServer(tools);
79:    const mcpConfig = {
80:      mcpServers: {
81:        'nexus-guild': {
82:          type: 'sse',
83:          url: mcpHandle.url,
84:        },
85:      },
86:    };
88:    const mcpConfigPath = path.join(tmpDir, 'mcp-config.json');
89:    fs.writeFileSync(mcpConfigPath, JSON.stringify(mcpConfig));
90:    args.push('--mcp-config', mcpConfigPath, '--strict-mcp-config');
91:  }
93:  return { tmpDir, args, mcpHandle };
94:}
96:// ── Output extraction ───────────────────────────────────────────────
98:/**
99: * Extract the final assistant text from a transcript.
100: *
101: * Walks the transcript backwards to find the last `assistant` message
102: * and concatenates its text content blocks.
103: *
104: * @internal Exported for testing only.
105: */
106:export function extractFinalAssistantText(transcript: Record<string, unknown>[]): string | undefined {
107:  for (let i = transcript.length - 1; i >= 0; i--) {
108:    const msg = transcript[i]!;
109:    if (msg.type !== 'assistant') continue;
111:    const message = msg.message as Record<string, unknown> | undefined;
112:    const content = message?.content as Array<Record<string, unknown>> | undefined;
113:    if (!content) continue;
115:    const text = content
116:      .filter((block) => block.type === 'text' && typeof block.text === 'string')
117:      .map((block) => block.text as string)
118:      .join('');
120:    return text || undefined;
121:  }
122:  return undefined;
123:}
125:// ── Result builder ──────────────────────────────────────────────────
127:function buildResult(raw: StreamJsonResult): SessionProviderResult {
128:  const status = raw.exitCode === 0 ? 'completed' as const : 'failed' as const;
129:  return {
130:    status,
131:    exitCode: raw.exitCode,
132:    error: status === 'failed' ? `claude exited with code ${raw.exitCode}` : undefined,
133:    costUsd: raw.costUsd,
134:    tokenUsage: raw.tokenUsage,
135:    providerSessionId: raw.providerSessionId,
136:    transcript: raw.transcript,
137:    output: extractFinalAssistantText(raw.transcript),
138:  };
139:}
141:// ── Provider implementation ──────────────────────────────────────────
143:const provider: AnimatorSessionProvider = {
144:  name: 'claude-code',
146:  launch(config: SessionProviderConfig): {
147:    chunks: AsyncIterable<SessionChunk>;
148:    result: Promise<SessionProviderResult>;
149:  } {
150:    // prepareSession is async (MCP server start), so we wrap the launch
151:    // in a promise. The chunks iterable bridges the async gap — it waits
152:    // for prep to complete before yielding.
154:    let chunkResolve: (() => void) | null = null;
155:    let innerChunks: AsyncIterable<SessionChunk> | null = null;
156:    let innerIterator: AsyncIterator<SessionChunk> | null = null;
157:    let prepDone = false;
158:    let prepError: Error | null = null;
159:    let done = false;
161:    const result = prepareSession(config).then(async ({ tmpDir, args, mcpHandle }) => {
162:      // Autonomous mode: prompt piped via stdin (--print - reads from stdin).
163:      // This avoids Commander parsing issues when the prompt starts with '-'
164:      // (e.g. YAML frontmatter '---') and also avoids OS arg length limits.
165:      const prompt = config.initialPrompt ?? '';
166:      args.push(
167:        '--print', '-',
168:        '--output-format', 'stream-json',
169:        '--verbose',
170:      );
172:      const cleanup = async () => {
173:        await mcpHandle?.close().catch(() => {});
174:        fs.rmSync(tmpDir, { recursive: true, force: true });
175:      };
177:      try {
178:        if (config.streaming) {
179:          const spawned = spawnClaudeStreamingJson(args, config.cwd, config.environment, prompt);
180:          innerChunks = spawned.chunks;
181:          prepDone = true;
182:          if (chunkResolve) { chunkResolve(); chunkResolve = null; }
184:          const raw = await spawned.result;
185:          await cleanup();
186:          return buildResult(raw);
187:        }
189:        // Non-streaming
190:        prepDone = true;
191:        done = true;
192:        if (chunkResolve) { chunkResolve(); chunkResolve = null; }
194:        const raw = await spawnClaudeStreamJson(args, config.cwd, config.environment, prompt);
195:        await cleanup();
196:        return buildResult(raw);
197:      } catch (err) {
198:        await cleanup();
199:        throw err;
200:      }
201:    }).catch((err) => {
202:      // If prep itself failed, unblock the chunk iterator
203:      prepError = err instanceof Error ? err : new Error(String(err));
204:      prepDone = true;
205:      done = true;
206:      if (chunkResolve) { chunkResolve(); chunkResolve = null; }
207:      throw err;
208:    });
210:    // Chunks iterable that bridges the async prep gap. In non-streaming
211:    // mode or on error, it completes immediately with no items.
212:    const chunks: AsyncIterable<SessionChunk> = {
213:      [Symbol.asyncIterator]() {
214:        return {
