1:import { z } from 'zod';
2:import { guild } from '@shardworks/nexus-core';
3:import { tool } from '@shardworks/tools-apparatus';
4:import type { ClerkApi } from '../types.ts';
6:export default tool({
7:  name: 'writ-cancel',
8:  description: 'Cancel a writ, transitioning it from new, ready, or active to cancelled',
9:  instructions:
10:    'Cancels the writ. Writs in new (draft), ready, or active status can all be cancelled. ' +
11:    'Optionally record a resolution explaining why. ' +
12:    'Returns the updated writ.',
13:  params: {
14:    id: z.string().describe('Writ id'),
15:    resolution: z.string().optional().describe('Optional summary of why the writ was cancelled'),
16:  },
